import{_ as e,H as a,f as i,i as r}from"./chunks/framework.Cvt1eIE0.js";const g=JSON.parse('{"title":"科研成果","description":"","frontmatter":{},"headers":[],"relativePath":"research.md","filePath":"research.md","lastUpdated":1779028675000}'),o={name:"research.md"};function n(l,t,d,s,h,m){return a(),i("div",null,[...t[0]||(t[0]=[r('<h1 id="科研成果" tabindex="-1">科研成果 <a class="header-anchor" href="#科研成果" aria-label="Permalink to &quot;科研成果&quot;">​</a></h1><h2 id="学术论文" tabindex="-1">学术论文 <a class="header-anchor" href="#学术论文" aria-label="Permalink to &quot;学术论文&quot;">​</a></h2><p>累计发表 SCI/EI 论文 11 篇，部分代表作：</p><h3 id="期刊论文-第一作者-通讯作者" tabindex="-1">期刊论文（第一作者/通讯作者） <a class="header-anchor" href="#期刊论文-第一作者-通讯作者" aria-label="Permalink to &quot;期刊论文（第一作者/通讯作者）&quot;">​</a></h3><ol><li><p><strong>B Li</strong>, H Zhao, Y Jiang, C Zhao. Enhanced Co-Simulation of Wind Energy Conversion Systems: A Mechanically Equivalent Interfacing Method. <em>IEEE Transactions on Sustainable Energy</em>, 2025, 17(2). (SCI, IF: 10.0)</p></li><li><p><strong>李冰</strong>, 赵浩然, 江艺宝, 田航, 王梦雪, Kai STRUNZ. 风电场全过程耦合精细化建模及其高效并行仿真算法. <em>电力系统自动化</em>, 2025, 49(23). (北大核心/EI)</p></li><li><p><strong>李冰</strong>, 赵浩然, 江艺宝, 孟铃涵, 魏小钊, Kai STRUNZ. 基于异构计算的大规模风电场精细化高效仿真技术. <em>电力系统自动化</em>, 2025, 49(24). (北大核心/EI)</p></li><li><p><strong>B Li</strong>, H Zhao, Y Jiang, L Meng. Real-time simulation for detailed wind turbine model based on heterogeneous computing. <em>International Journal of Electrical Power &amp; Energy Systems</em>, 2023, 155. (SCI, IF: 5.0)</p></li><li><p><strong>B Li</strong>, H Zhao, K Zhang. A heterogeneous accelerated simulation framework for wind field dynamic model. <em>IET Renewable Power Generation</em>, 2023, 17(1). (SCI, IF: 2.9)</p></li><li><p><strong>B Li</strong>, H Zhao, S Gao, S Hu. Digital real-time co-simulation platform of refined wind energy conversion system. <em>International Journal of Electrical Power &amp; Energy Systems</em>, 2020, 117. (SCI, IF: 5.0)</p></li></ol><h3 id="合作论文" tabindex="-1">合作论文 <a class="header-anchor" href="#合作论文" aria-label="Permalink to &quot;合作论文&quot;">​</a></h3><ol start="7"><li><p>H Zhao, C Zhao, <strong>B Li*</strong>, L Tan. Stability-improved network partition based on a small-step model for electromagnetic transient simulation. <em>International Journal of Electrical Power &amp; Energy Systems</em>, 2026, Early Access. (SCI, IF: 5.0, 通讯)</p></li><li><p>T Liu, Y Jiang, H Zhao, <strong>B Li</strong>, K Strunz. Fine-Grained Optimal Allocation of Wind Farm Decoupled Models for CPU-GPU Parallel EMT Simulation. <em>IEEE Transactions on Energy Conversion</em>, 2026, Early Access. (SCI, IF: 5.6)</p></li><li><p>J Yu, H Zhao, Y Jiang, <strong>B Li</strong>, L Meng, F Yang. Efficient Electromagnetic Transient Simulation for DFIG-Based Wind Farms Using Network Partitioning. <em>International Journal of Electrical Power &amp; Energy Systems</em>, 2024, 162. (SCI, IF: 5.0)</p></li><li><p>赵浩然, 孟铃涵, 江艺宝, <strong>李冰</strong>. 面向新型电力系统的实时仿真平台综述与展望. <em>高电压技术</em>, 2024, 50(10). (北大核心/EI)</p></li><li><p>江艺宝, 于佳乐, 赵浩然, <strong>李冰</strong>, 韩明哲, 赵长旺. 新型电力系统电磁暂态并行仿真关键技术及展望. <em>高电压技术</em>, 2024, 50(07). (北大核心/EI)</p></li></ol><h2 id="学术专著" tabindex="-1">学术专著 <a class="header-anchor" href="#学术专著" aria-label="Permalink to &quot;学术专著&quot;">​</a></h2><ul><li>赵浩然, <strong>李冰</strong>, 许建中, 秦世耀, 江艺宝, 王鹏. 《风电场精细化建模仿真技术》. 机械工业出版社, 2025. (个人撰写 25 万字 / 总计 39.3 万字)</li></ul><h2 id="发明专利" tabindex="-1">发明专利 <a class="header-anchor" href="#发明专利" aria-label="Permalink to &quot;发明专利&quot;">​</a></h2><p>累计授权国家发明专利 <strong>11 项</strong>：</p><ol><li>一种精细化风能转换系统的实时联合仿真平台及仿真方法, ZL201910749374.6, 2021.02 (2/2)</li><li>一种电磁与机电实时混合仿真方法及装置, ZL202410619739.4, 2024.09 (3/6)</li><li>一种基于异构型硬件的风电机组实时仿真平台及方法, ZL202211053344.X, 2024.09 (3/3)</li><li>一种风电机组精细化接口仿真方法、系统、终端及介质, ZL202510621766.X, 2025.08 (3/3)</li><li>一种基于小步合成的电磁暂态仿真解耦方法、系统及介质, ZL202511036873.2, 2025.07 (3/4)</li><li>一种基于双重输入凸神经网络的风电场有功减载优化方法, ZL202510570229.7, 2025.07 (3/6)</li><li>基于数据机理混合建模的风电场疲劳抑制有功控制方法, ZL202510534273.2, 2025.10 (3/6)</li><li>一种风电场的有功减载优化控制方法、系统、设备和存储介质, ZL202411963115.0, 2025.07 (3/4)</li><li>基于双层分网的直驱风电场并行仿真方法、系统、终端及介质, ZL202410382257.1, 2024.06 (4/8)</li><li>风电场分群尾流优化方法及系统, ZL202410391204.6, 2024.06 (4/7)</li><li>一种基于模型预测控制与流场降阶的风电场尾流恢复优化方法, ZL202410774211.4, 2024.10 (4/7)</li></ol><h2 id="科研项目" tabindex="-1">科研项目 <a class="header-anchor" href="#科研项目" aria-label="Permalink to &quot;科研项目&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目名称</th><th>角色</th><th>类别</th><th>资助机构</th><th>经费</th><th>年限</th></tr></thead><tbody><tr><td>信息能源耦合节点能量一致标度及其自适应持续进化建模</td><td>主要参与人</td><td>国家重点研发计划课题</td><td>科技部</td><td>487 万</td><td>5 年</td></tr><tr><td>全生命周期电力碳足迹溯源与建模技术研究</td><td>主要参与人</td><td>国家科技重大专项课题</td><td>科技部</td><td>701.5 万</td><td>3 年</td></tr></tbody></table><h2 id="科研获奖" tabindex="-1">科研获奖 <a class="header-anchor" href="#科研获奖" aria-label="Permalink to &quot;科研获奖&quot;">​</a></h2><table tabindex="0"><thead><tr><th>获奖项目</th><th>奖励名称</th><th>授奖单位</th><th>获奖时间</th><th>本人排序</th></tr></thead><tbody><tr><td>大规模风电场气-弹-机-电多尺度混合建模与实时仿真关键技术及应用</td><td>中国仿真学会科学技术奖一等奖</td><td>中国仿真学会（全国性一级学会）</td><td>2025.10</td><td>4/15</td></tr><tr><td>风电机组数字孪生系统</td><td>日内瓦国际发明展银奖</td><td>瑞士联邦政府、日内瓦州政府、世界知识产权组织</td><td>2022.03</td><td>2/5</td></tr><tr><td>风电场精细化实时仿真平台</td><td>中国研究生电子设计竞赛全国总决赛团队一等奖（全国唯一）</td><td>中国电子学会</td><td>2023.08</td><td>3/3</td></tr></tbody></table>',16)])])}const p=e(o,[["render",n]]);export{g as __pageData,p as default};
